+    fn generation(&self, collection: &str) -> Result<u64> {
+        let g = self.mappings.read().expect("poisoned");
+        let m = g.get(collection).ok_or_else(|| RuLakeError::UnknownCollection {
+            backend: self.id.clone(),
+            collection: collection.to_string(),
